{
  lib,
  buildNpmPackage,
  fetchurl,
  nodejs,
  makeWrapper,
}:

let
  version = "0.9.1";

  # Pre-built package from npm registry (pnpm monorepo source is complex to build)
  npmTarball = fetchurl {
    url = "https://registry.npmjs.org/vde-monitor/-/vde-monitor-${version}.tgz";
    hash = "REDACTED";
  };
in
buildNpmPackage {
  pname = "vde-monitor";
  inherit version;

  # Unpack npm tarball (extracts to `package/`)
  src = npmTarball;
  sourceRoot = "package";

  # package-lock.json is not included in the npm tarball, so we provide
  # a minimal one that lists the runtime dependencies.
  postPatch = ''
    cat > package-lock.json << 'LOCK'
    ${builtins.readFile ./vde-monitor-lock.json}
    LOCK
  '';

  npmDepsHash = "REDACTED";

  # dist/ is already built in the npm tarball
  dontNpmBuild = true;

  nativeBuildInputs = [ makeWrapper ];

  postInstall = ''
    for bin in vde-monitor vde-monitor-hook vde-monitor-summary; do
      wrapProgram "$out/bin/$bin" --prefix PATH : ${lib.makeBinPath [ nodejs ]}
    done
  '';

  meta = with lib; {
    description = "Monitor tmux/WezTerm coding sessions from a browser";
    homepage = "https://github.com/yuki-yano/vde-monitor";
    license = licenses.mit;
    platforms = platforms.linux ++ platforms.darwin;
    mainProgram = "vde-monitor";
  };
}

