# Voxtype voice input (whisper.cpp, Vulkan GPU acceleration)
programs.voxtype = {
  enable = true;
  engine = "whisper";
  package = voxtype.packages.${pkgs.stdenv.hostPlatform.system}.vulkan;
  model.name = "large-v3-turbo";
  service.enable = true;
  settings = {
    state_file = "auto";
    hotkey = {
      enabled = false;
      key = "SCROLLLOCK";
      modifiers = [ ];
      mode = "toggle";
    };
    audio = {
      device = "default";
      sample_rate = 16000;
      max_duration_secs = 60;
      feedback = {
        enabled = true;
        theme = "default";
        volume = 0.7;
      };
